/// Base64-encoded tray status icons (36px RGBA PNGs), generated by
/// `tool/gen_tray_icons.py` (a port of the menu-bar app's `status_icon`): three
/// water-ripple waves in neutral gray with a state badge — none (stopped),
/// amber ring (starting), green dot (running), red "!" (needs Tailscale login).
/// Embedded as base64 so no asset wiring is needed; loaded via
/// `Image.fromBase64`.
library;

class TrayIcons {
  TrayIcons._();

  static const String stopped = '';

  static const String starting = '';

  static const String running = '';

  static const String needsLogin = '';
}
